    //      A
    //     / \
    //    B   C
    //   / \
    //  D   E
    // 
    // After rotation:
    //     B
    //    / \
    //   D   A
    //      / \
    //     E   C

    const tree = RedBlackTree("A", 0, null, null, null);
    tree.left = RedBlackTree("B", 0, tree, null, null);
    tree.right = RedBlackTree("C", 0, tree, null, null);
    tree.left.left = RedBlackTree("D", 0, tree.left, null, null);
    tree.left.right = RedBlackTree("E", 0, tree.left, null, null);

    // Perform rotation
    const newRoot = tree.rotate_right();

    // Assertions
    console.assert(newRoot.label === "B", "New root should be B");
    console.assert(newRoot.left.label === "D", "Left child should be D");
    console.assert(newRoot.right.label === "A", "Right child should be A");
    console.assert(newRoot.right.left.label === "E", "Right-left child should be E");
    console.assert(newRoot.right.right.label === "C", "Right-right child should be C");

    // Check parent pointers
    console.assert(newRoot.parent === null, "New root's parent should be null");
    console.assert(newRoot.left.parent === newRoot, "D's parent should be B");
    console.assert(newRoot.right.parent === newRoot, "A's parent should be B");
    console.assert(newRoot.right.left.parent === newRoot.right, "E's parent should be A");
    console.assert(newRoot.right.right.parent === newRoot.right, "C's parent should be A");

    console.log("Basic rotate right test passed!");
}

// Test that rotate_right returns the original node when there's no left child
function testRotateRightNoLeftChild() {
    const tree = RedBlackTree("A", 0, null, null, null);
    tree.right = RedBlackTree("C", 0, tree, null, null);

    // No left child, so should return original tree
    const result = tree.rotate_right();
    console.assert(result === tree, "Should return the same tree reference");
    console.assert(result.label === "A", "Root should still be A");

    console.log("Rotate right with no left child test passed!");
}

// Test rotation when the left child has no right child
function testRotateRightWithNullRightOfLeft() {
    const tree = RedBlackTree("A", 0, null, null, null);
    tree.left = RedBlackTree("B", 0, tree, null, null);
    tree.right = RedBlackTree("C", 0, tree, null, null);
    tree.left.left = RedBlackTree("D", 0, tree.left, null, null);

    const newRoot = tree.rotate_right();

    console.assert(newRoot.label === "B", "New root should be B");
    console.assert(newRoot.left.label === "D", "Left child should be D");
    console.assert(newRoot.right.label === "A", "Right child should be A");
    console.assert(newRoot.right.left === null, "A's left child should be null");
    console.assert(newRoot.right.right.label === "C", "A's right child should be C");

    console.log("Rotate right with null right of left child test passed!");
}

// Test rotation when the node has a parent
function testRotateRightWithParent() {
    // Create a tree with a parent node where tree is the left child
    let parent = RedBlackTree("P", 0, null, null, null);
    let tree = RedBlackTree("A", 0, parent, null, null);
    parent.left = tree;  // Set as left child

    tree.left = RedBlackTree("B", 0, tree, null, null);
    tree.right = RedBlackTree("C", 0, tree, null, null);
    tree.left.left = RedBlackTree("D", 0, tree.left, null, null);
    tree.left.right = RedBlackTree("E", 0, tree.left, null, null);

    // Perform rotation
    const newRoot = tree.rotate_right();

    // Check new root is connected correctly to parent
    console.assert(newRoot.parent === parent, "New root's parent should be P");
    console.assert(parent.left === newRoot, "Parent's left child should be the new root B");

    // Additional test with parent.right = tree
    parent = RedBlackTree("P", 0, null, null, null);
    tree = RedBlackTree("A", 0, parent, null, null);
    parent.right = tree;  // Set as right child

    tree.left = RedBlackTree("B", 0, tree, null, null);
    tree.right = RedBlackTree("C", 0, tree, null, null);
    tree.left.left = RedBlackTree("D", 0, tree.left, null, null);
    tree.left.right = RedBlackTree("E", 0, tree.left, null, null);

    // Perform rotation
    const newRoot2 = tree.rotate_right();

    // Check new root is connected correctly to parent
    console.assert(newRoot2.parent === parent, "New root's parent should be P");
    console.assert(parent.right === newRoot2, "Parent's right child should be the new root B");

    console.log("Rotate right with parent test passed!");
}

