        // The node should not be identified as a left child (no parent)
        const result = node.is_left();
        console.assert(result === false, "Expected false when node has no parent");
        console.log("Test is_left when node has no parent: " + (result === false ? "PASS" : "FAIL"));
        return result === false;
    }

    // Test when parent has no left child
    function testIsLeftParentWithNoLeft() {
        // Create a parent node with only a right child
        const parent = RedBlackTree(10, 0, null, null, null);
        const child = RedBlackTree(15, 0, parent, null, null);
        parent.right = child;  // Set child as right child
        parent.left = null;    // Explicitly set left child to None

        // The child should not be identified as the left child
        const result = child.is_left();
        console.assert(result === false, "Expected false when parent has no left child");
        console.log("Test is_left when parent has no left child: " + (result === false ? "PASS" : "FAIL"));
        return result === false;
    }

    // Run all tests and collect results
    const results = [
